sys_script_client.script:
function onSubmit() {

    var reorderLevel = g_form.getValue('reorder_level');
    var reorderQty = g_form.getValue('reorder_quantity');

    if (reorderLevel <= 0) {
        g_form.addErrorMessage('Reorder Level must be a positive number greater than zero.');
        return false;
    }
    if (reorderQty <= 0) {
        g_form.addErrorMessage('Reorder Quantity must be a positive number greater than zero.');
        return false;
    }

    if (Number(reorderQty) <= Number(reorderLevel)) {
        g_form.addErrorMessage('Reorder Quantity must be greater than Reorder Level.');
        return false;
    }


    return true;
}
